-- AuctionIQ: PostgreSQL Database Schema and Data Initialization Script
-- Created for cricket scouting and decision intelligence platform.

-- 1. DROP TABLES IF THEY EXIST (order respect foreign keys)
DROP TABLE IF EXISTS saved_reports;
DROP TABLE IF EXISTS players;
DROP TABLE IF EXISTS users;

-- 2. CREATE USERS TABLE
CREATE TABLE users (
    id SERIAL PRIMARY KEY,
    username VARCHAR(50) NOT NULL UNIQUE,
    password VARCHAR(255) NOT NULL,
    email VARCHAR(100) NOT NULL UNIQUE,
    role VARCHAR(20) NOT NULL,
    favorite_team VARCHAR(20)
);

-- 3. CREATE PLAYERS TABLE
CREATE TABLE players (
    id SERIAL PRIMARY KEY,
    name VARCHAR(100) NOT NULL,
    role VARCHAR(50) NOT NULL,
    batting_style VARCHAR(50),
    bowling_style VARCHAR(50),
    country VARCHAR(50) NOT NULL,
    ipl_team VARCHAR(50),
    base_price DOUBLE PRECISION NOT NULL,
    sold_price DOUBLE PRECISION,
    matches_played INTEGER,
    runs_scored INTEGER,
    batting_average DOUBLE PRECISION,
    strike_rate DOUBLE PRECISION,
    wickets_taken INTEGER,
    bowling_average DOUBLE PRECISION,
    economy_rate DOUBLE PRECISION,
    overs_bowled DOUBLE PRECISION,
    rating DOUBLE PRECISION NOT NULL
);

-- 4. CREATE SAVED_REPORTS TABLE
CREATE TABLE saved_reports (
    id SERIAL PRIMARY KEY,
    user_id INTEGER NOT NULL,
    player_id INTEGER NOT NULL,
    report_content TEXT NOT NULL,
    generated_at TIMESTAMP NOT NULL,
    CONSTRAINT fk_saved_reports_users FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    CONSTRAINT fk_saved_reports_players FOREIGN KEY (player_id) REFERENCES players(id) ON DELETE CASCADE
);

